    diff: Vec<i64>, 
}

impl DSU {
    fn new(n: usize) -> Self {
        DSU {
            parent: (0..n).collect(),
            diff: vec![0; n],
        }
    }

    // Finds the root of node i and calculates the parity distance from i to the root.
    // Returns (root: usize, distance: i64 (0 or 1))
