        let (root, root_dist) = self.find(self.parent[i]);

        // Path compression: Update parent[i] directly to root
        self.parent[i] = root;

        // Update distance[i]: new_dist(i -> root) = old_dist(i -> parent[i]) XOR dist(parent[i] -> root)
        self.diff[i] ^= root_dist;

        (root, self.diff[i])
    }
}

fn solve(n_i64: i64, edges: Vec<Vec<i64>>) -> i64 {
    let n = n_i64 as usize;
    let mut dsu = DSU::new(n);
    let mut added_edges_count = 0;

    for edge in edges {
        // u, v, w are i64
        let u = edge[0] as usize;
        let v = edge[1] as usize;
        let w = edge[2]; // w is 0 or 1

        // Find roots and distances
        let (ru, du) = dsu.find(u);
        let (rv, dv) = dsu.find(v);

        if ru == rv {
            // u and v are already in the same component. Adding (u, v) creates a cycle.

            // Cycle weight parity = (du XOR dv) XOR w
            let cycle_weight_parity = du ^ dv ^ w;

            // Edge is added if cycle weight is even (parity 0).
            if cycle_weight_parity == 0 {
                added_edges_count += 1;
            }
        } else {
            // u and v are in different components. Edge is always added.
            added_edges_count += 1;

            // Union operation: Merge ru's component into rv's component (make rv the parent of ru).
            dsu.parent[ru] = rv;

            // Calculate the new distance[ru], which is the parity distance from ru to rv.
            // parity(ru -> rv) = parity(ru -> u) XOR w XOR parity(v -> rv)
            // Since du = parity(u -> ru), parity(ru -> u) = du.
            // Since dv = parity(v -> rv), parity(v -> rv) = dv.
            dsu.diff[ru] = du ^ w ^ dv;
        }
    }

    added_edges_count
