    // diff[i] stores the parity (0 or 1) of the path weight from node i to its current parent.
    diff: Vec<i64>, 
}

impl DSU {
    fn new(n: usize) -> DSU {
        DSU {
            parent: (0..n).collect(),
            diff: vec![0; n],
        }
    }

    // Finds the root of node i and returns (root, distance_to_root_parity).
    fn find(&mut self, i: usize) -> (usize, i64) {
        if self.parent[i] == i {
            return (i, 0);
        }

        // Recursively find root and distance from parent[i] to root
        let (root, root_dist) = self.find(self.parent[i]);

        // Path compression
        self.parent[i] = root;

        // Update distance[i]: new_dist(i -> root) = old_dist(i -> parent[i]) XOR dist(parent[i] -> root)
        // Note: XOR operation is used for parity tracking (mod 2).
        self.diff[i] ^= root_dist;

        (root, self.diff[i])
    }

    // Attempts to add edge (u, v) with weight w. Returns true if added.
    fn try_union(&mut self, u: usize, v: usize, w: i64) -> bool {
        let (root_u, dist_u) = self.find(u);
        let (root_v, dist_v) = self.find(v);

        if root_u == root_v {
            // u and v are in the same component. Adding the edge creates a cycle.

            // Path parity (u -> v) = dist_u XOR dist_v.
            // Cycle weight = Path parity XOR new edge weight w.
            // Condition for even cycle weight: (dist_u ^ dist_v ^ w) == 0
            if (dist_u ^ dist_v ^ w) == 0 {
                return true; // Edge added
            } else {
                return false; // Edge rejected (odd cycle)
            }
        } else {
            // u and v are in different components. The edge is always added.

            // Union operation: Merge root_u component into root_v component.
            self.parent[root_u] = root_v;

            // Calculate the new distance[root_u] (parity distance from root_u to root_v).
            // Path: r_u -> u -> v -> r_v
            // Parity(r_u -> r_v) = Parity(r_u -> u) XOR Parity(u -> v) XOR Parity(v -> r_v)
            // Parity(r_u -> u) = dist_u
            // Parity(u -> v) = w
            // Parity(v -> r_v) = dist_v
            self.diff[root_u] = dist_u ^ w ^ dist_v;

            return true; // Edge added
        }
    }
}

fn solve(n: i64, edges: Vec<Vec<i64>>) -> i64 {
    let N = n as usize;
    let mut dsu = DSU::new(N);
