/**
 * @param {number} n
 * @param {number[][]} edges
 * @return {number}
 */
function solve(n, edges) {
    // DSU structure
    const parent = Array(n).fill(0).map((_, i) => i);
    // diff[i] stores the parity of the path weight from node i to its current parent.
    const diff = Array(n).fill(0);

    /**
     * Finds the root of node i and calculates the parity distance from i to the root.
     * @param {number} i
     * @returns {{root: number, distance: number}} - {root, distance (0 or 1)}
     */
    function find(i) {
        if (parent[i] === i) {
            return { root: i, distance: 0 };
        }

        // Recursively find root and distance from parent[i] to root
        const { root, distance: rootDist } = find(parent[i]);

        // Path compression: Update parent[i] directly to root
        parent[i] = root;

        // Update distance[i]: new_dist(i -> root) = old_dist(i -> parent[i]) XOR dist(parent[i] -> root)
        diff[i] = diff[i] ^ rootDist;

        return { root: root, distance: diff[i] };
    }

    let addedEdgesCount = 0;

    for (const edge of edges) {
        const [u, v, w] = edge;

        const { root: ru, distance: du } = find(u);
        const { root: rv, distance: dv } = find(v);

        if (ru === rv) {
            // u and v are already in the same component. Adding (u, v) creates a cycle.

            // Path weight from u to v through existing edges: du XOR dv
            // Cycle weight = Path weight + new edge weight w
            // Condition for even cycle weight: (du XOR dv) XOR w == 0
            if ((du ^ dv ^ w) === 0) {
                addedEdgesCount++;
            }
            // If the cycle weight is odd, the edge is rejected.
        } else {
            // u and v are in different components. The edge is always added as it doesn't create a cycle.
            // Union operation: Merge ru's component into rv's component (arbitrary choice).

            // We set parent[ru] = rv.
            parent[ru] = rv;

            // Calculate the new distance[ru], which is the parity distance from ru to rv.
            // Path: ru -> u -> v -> rv
            // Weight = dist(ru -> u) XOR w XOR dist(v -> rv)
            // dist(ru -> u) = du
            // dist(v -> rv) = dv
            // dist(ru -> rv) = du XOR w XOR dv
            diff[ru] = du ^ w ^ dv;

            addedEdgesCount++;
        }
    }

    return addedEdgesCount;
}
